import os
import json
from pika import BasicProperties, ConnectionParameters
from pika.exceptions import AMQPConnectionError

# RabbitMQ connection parameters
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
RABBITMQ_USERNAME = 'guest'
RABBITMQ_PASSWORD = 'guest'

# Task queue name
TASK_QUEUE_NAME = 'tasks'

def connect_to_rabbitmq():
    try:
        credentials = ConnectionParameters(
            host=RABBITMQ_HOST,
            port=RABBITMQ_PORT,
            credentials=BasicProperties(
                username=RABBITMQ_USERNAME,
                password=RABBITMQ_PASSWORD
            )
        )
        
        connection = pika.BlockingConnection(credentials)
        channel = connection.channel()
        
        # Declare the task queue if it doesn't exist
        channel.queue_declare(queue=TASK_QUEUE_NAME, durable=True)
        
        return channel, connection
    
    except AMQPConnectionError as e:
        print(f"Failed to connect to RabbitMQ: {e}")
        exit(1)

def publish_task(channel, task):
    properties = BasicProperties(
        content_type='application/json',
        delivery_mode=2  # Make message persistent
    )
    
    channel.basic_publish(exchange='',
                          routing_key=TASK_QUEUE_NAME,
                          body=json.dumps(task),
                          properties=properties)
    
    print(f"Published task: {task}")

def consume_tasks(channel):
    def callback(ch, method, properties, body):
        try:
            # Process the task
            task = json.loads(body)
            print(f"Processing task: {task}")
            
            # Simulate processing time
            import time
            time.sleep(2)
            
            print(f"Task processed successfully")
        
        except Exception as e:
            print(f"Error processing task: {e}")
    
    channel.basic_consume(queue=TASK_QUEUE_NAME,
                          on_message_callback=callback,
                          no_ack=False)

def main():
    channel, connection = connect_to_rabbitmq()
    
    # Example publisher
    task = {'id': 1, 'name': 'Example Task'}
    publish_task(channel, task)
    
    # Start consuming tasks
    consume_tasks(channel)
    
    try:
        while True:
            pass
    
    except KeyboardInterrupt:
        print("Stopping RabbitMQ consumer")
        
        connection.close()

if __name__ == '__main__':
    main()